from minipackaging import Requirement, Version

def resolve(roots, candidates, env=None, requested_extras=None, prereleases=None):
    rows = []
    for c in candidates:
        rows.append({'name': Requirement(c['name']).name, 'version': Version(c['version']), 'requires': list(c.get('requires', []))})
    constraints = {}
    extras = {}
    edges = set()
    done = {}

    def add(req):
        constraints.setdefault(req.name, []).append(req)
        extras.setdefault(req.name, set()).update(req.extras)

    def specifier_facts(req):
        versions = sorted([r['version'] for r in rows if r['name'] == req.name])
        return tuple((str(v), req.specifier.contains(v, prereleases=prereleases)) for v in versions)

    for root in roots:
        req = root if isinstance(root, Requirement) else Requirement(root)
        if req.marker is None or req.marker.evaluate(env, requested_extras):
            add(req)

    while True:
        changed = False
        for name in sorted(constraints):
            opts = [r for r in rows if r['name'] == name and all(req.specifier.contains(r['version'], prereleases=prereleases) for req in constraints[name])]
            if not opts:
                raise ValueError(name)
            pick = max(opts, key=lambda r: r['version'])
            key = (str(pick['version']), tuple(sorted(extras.get(name, set()))))
            if done.get(name) == key:
                continue
            done[name] = key
            for text in pick['requires']:
                dep = Requirement(text)
                marker_applicable = dep.marker is None or dep.marker.evaluate(env, extras.get(name, set()))
                if marker_applicable:
                    edge = (name, dep.name, tuple(sorted(dep.extras)), dep.url, specifier_facts(dep), marker_applicable)
                    if edge not in edges:
                        edges.add(edge)
                        add(dep)
                        changed = True
        if not changed:
            break

    selected = {}
    excluded = {}
    for name in sorted(constraints):
        opts = [r for r in rows if r['name'] == name and all(req.specifier.contains(r['version'], prereleases=prereleases) for req in constraints[name])]
        if not opts:
            raise ValueError(name)
        pick = max(opts, key=lambda r: r['version'])
        selected[name] = str(pick['version'])
        rest = [str(r['version']) for r in rows if r['name'] == name and str(r['version']) != selected[name]]
        if rest:
            excluded[name] = sorted(rest, key=Version)
    edge_rows = [
        {'parent': p, 'name': n, 'extras': x, 'url': u, 'specifier_matches': s, 'marker_applicable': m}
        for p, n, x, u, s, m in sorted(edges, key=repr)
    ]
    dependents = {}
    for e in edge_rows:
        dependents.setdefault(e['name'], []).append(e['parent'])
    dependents = {k: sorted(set(v)) for k, v in sorted(dependents.items())}
    return {'selected': selected, 'edges': edge_rows, 'dependents': dependents, 'excluded': excluded}
